import type { Metadata } from "next";
import {
  Geist,
  Geist_Mono,
  DM_Sans,
  Playfair_Display,
  Noto_Sans_Bengali,
} from "next/font/google";
import "./globals.css";
import { AppProviders } from "@/lib/providers/AppProviders";

const geistSans = Geist({
  variable: "--font-geist-sans",
  subsets: ["latin"],
});

const geistMono = Geist_Mono({
  variable: "--font-geist-mono",
  subsets: ["latin"],
});

const dmSans = DM_Sans({
  variable: "--font-dm-sans",
  subsets: ["latin"],
  weight: ["400", "500", "700"],
});

const playfairDisplay = Playfair_Display({
  variable: "--font-playfair-display",
  subsets: ["latin"],
});

const notoSansBengali = Noto_Sans_Bengali({
  variable: "--font-noto-sans-bengali",
  subsets: ["bengali"],
  weight: ["400", "500", "700"],
});

export const metadata: Metadata = {
  title: "Expro Welfare Foundation",
  description: "Generated by create next app",
  icons: {
    icon: [
      { url: "/favicon.png" },
      { url: "/favicon.png", sizes: "32x32", type: "image/png" },
    ],
    shortcut: "/favicon.png",
    apple: "/favicon.png",
  },
};

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <html lang="en" suppressHydrationWarning>
      <body
        className={`${geistSans.variable} ${geistMono.variable} ${dmSans.variable} ${playfairDisplay.variable} ${notoSansBengali.variable} antialiased`}
        suppressHydrationWarning
      >
        {/* Wrap children with all providers (React Query, Auth, Notifications, Cart, Toast) */}
        <AppProviders>{children}</AppProviders>
      </body>
    </html>
  );
}
